class Solution:
    def minOperations(self, nums) -> int:
        def is_prime(x):
            if x < 2:
                return False
            for d in range(2, int(x ** 0.5) + 1):
                if x % d == 0:
                    return False
            return True
        ops = 0
        for i, v in enumerate(nums):
            if i % 2 == 0:
                x = v
                while not is_prime(x):
                    x += 1
                ops += x - v
            else:
                x = v
                while is_prime(x):
                    x += 1
                ops += x - v
        return ops

