class Solution:
    def minOperations(self, nums) -> int:
        def is_prime(x):
            if x < 2:
                return False
            if x < 4:
                return True
            if x % 2 == 0:
                return False
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        ops = 0
        for i, v in enumerate(nums):
            if i % 2 == 0:
                x = v
                while not is_prime(x):
                    x += 1
                ops += x - v
            else:
                x = v
                while is_prime(x):
                    x += 1
                ops += x - v
        return ops

