function isPrime(x) {
    if (x < 2) return false;
    if (x < 4) return true;
    if (x % 2 === 0) return false;
    for (let i = 3; i * i <= x; i += 2) {
        if (x % i === 0) return false;
    }
    return true;
}
var minOperations = function(nums) {
    let ops = 0;
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (i % 2 === 0) {
            let x = v;
            while (!isPrime(x)) x++;
            ops += x - v;
        } else {
            let x = v;
            while (isPrime(x)) x++;
            ops += x - v;
        }
    }
    return ops;
};
